#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    int countPrimes(int n) {
        if (n <= 1) return 0;
        vector<bool> sieve(n);
        for (int i = 2; i <= sqrt(n); i++) {
            if (sieve[i]) {
                for (int j = i * i; j < n; j += i) {
                    sieve[j] = false;
                }
            }
        }
        int res = 0;
        for (bool x : sieve) {
            if (x) res++;
        }
        return res;
    }
};

int main() {
    int n;
    cin >> n;
    Solution solution;
    cout << solution.countPrimes(n) << endl;
    return 0;
}
